def can_user_perform_action(active_user_id, proj_id, operation):
    user_role, project_owner = get_user_role_and_project_owner(active_user_id, proj_id)

    if user_role == "admin":
        return True

    if user_role == "user" and active_user_id == project_owner:
        return True

    return False

